from src.reasoning_client import _extract_json

# Test edge cases in fence stripping
test_cases = [
    ('```\n{"a": 1}\n```', {"a": 1}, "basic fence"),
    ('```json\n{"a": 1}\n```', {"a": 1}, "json fence"),
    ('```JSON\n{"a": 1}\n```', {"a": 1}, "uppercase JSON"),
    ('```\n```\n', None, "empty fences"),
    ('```{"a": 1}', None, "unclosed fence"),
    ('```json{"a": 1}', None, "json label no newline, unclosed"),
    ('```\njunk', None, "unclosed fence with junk"),
]

for inp, expected_val, desc in test_cases:
    try:
        result = _extract_json(inp)
        if expected_val is None:
            print(f"FAIL: {desc}: expected error but got {result!r}")
        elif result == expected_val:
            print(f"PASS: {desc}")
        else:
            print(f"FAIL: {desc}: got {result!r}, expected {expected_val!r}")
    except Exception as e:
        if expected_val is None:
            print(f"PASS: {desc} (correctly raised {type(e).__name__})")
        else:
            print(f"FAIL: {desc}: got error {e}, expected {expected_val!r}")
EOF
